public void OnRewardSelected()
    {
        // ✅ [AUD-Anti] 1회용 완료 콜백 실행 (SkillScholar 등에서 OnNodeCompleted 지연)
        if (OnRewardDoneCallback != null)
        {
            var done = OnRewardDoneCallback;
            OnRewardDoneCallback = null;
            done.Invoke();
        }

        // ✅ [Round 120] 보스 격파 특별 보상 후 처리 — OnPostBossRewardComplete 콜백 우선
        // 보스전 후 특별 보상을 선택했으면 콜백(OnRunComplete 등)을 실행하고 종료
        var tbc = BattleController.Instance;
        if (tbc?.OnPostBossRewardComplete != null)
        {
            var cb = tbc.OnPostBossRewardComplete;
            tbc.OnPostBossRewardComplete = null; // 1회 소비
            // ✅ [2026-06-14 Codex P2] 콜백 소비 직후 pending=false 즉시 커밋 — RewardSelected 스냅샷(콜백 소비 ★전★)에
            //   SnapshotPendingPostBossReward=true 가 박혀, 보상 적용 후 콜백 완료 전 종료/크래시 시 보스보상 재출현(중복 수령) 차단.
            GameFlow.Instance?.RequestMidRunSnapshot("BossRewardConsumed", force: true);
            cb.Invoke();
            return; // 맵 복귀 생략 — 런 완료 화면으로 이동
        }

        // ★ [2026-06-10] 런 종료(RunEnding/GameOver) 중 보상 선택(승리 해금 픽 등) 후 맵 복귀 차단 —
        //   OnPostBossRewardComplete 소비 후 뜨는 종료기 보상에서 ReturnToMap 이 맵+타이머를 되살리던 버그.
        //   종료 흐름은 자체 씬 전환(Scenes.Victory 등)이 처리하므로 여기서는 복귀하지 않는다.
        var endPhase = GameFlow.Instance != null ? GameFlow.Instance.CurrentRunPhase : GameFlow.RunPhase.Lobby;
        if (endPhase == GameFlow.RunPhase.RunEnding || endPhase == GameFlow.RunPhase.GameOver)
        {
            Debug.Log("[RewardUI] 런 종료 중 보상 선택 — 맵 복귀 생략");
            return;
        }

        // ✅ 레벨업 큐 — 대기 중인 레벨업이 있으면 맵 복귀 대신 다음 레벨업 처리
        if (_isLevelUpReward && PlayerLevel.Instance != null)
        {
            PlayerLevel.Instance.OnLevelUpRewardComplete();
            // ProcessNextLevelUp()이 ShowRewards를 다시 호출했으면 여기서 리턴
            // 큐가 비었으면 맵 복귀로 진행
            bool rewardUiReopened = RootPanel != null ? RootPanel.activeSelf : gameObject.activeSelf;
            if (rewardUiReopened) return; // 실제 보상 패널이 다시 열렸으면 리턴
        }

        // ✅ [2026-06-14 Codex P2] 재개된 노드 보상 — 노드는 이미 완료(스냅샷)이므로 ReturnToMap 의 OnEncounterCompleted
        //   재호출(노드 이중완료=NodesCompleted/유대XP/메타챌린지 중복)을 ★건너뛰고★ 맵 복귀만. 일반 선택은 아래 ReturnToMap.
        if (_resumedNodeReward)
        {
            _resumedNodeReward = false;
            // 맵 복귀 직전 force 스냅샷 — "보상 소비됨+맵 복귀" 상태 원자 커밋(재개 후 재크래시 시 pending 재출현 차단).
            //   이 시점 RewardUI 패널은 Close()로 비활성 → IsNodeRewardPending=false 로 SnapshotPendingNodeReward 커밋.
            GameFlow.Instance?.RequestMidRunSnapshot("ResumedNodeReward.Return", force: true);
            if (GameFlow.Instance != null) GameFlow.Instance.ShowMapPanel();
            else { MapManager.Instance?.EndNodeInteractionPause(); MapUI.Instance?.ShowMap(); }
            return;
        }

        // ✅ [AUD-CDX-88001] NodeExecutor null 시 완료 라이프사이클 보장
        if (NodeExecutor.Instance != null)
        {
            NodeExecutor.Instance.ReturnToMap();
            // ReturnToMap이 OnEncounterCompleted + ShowMapPanel/ShowMap까지 처리하므로 이후 호출 없음
        }
        else
        {
            GameFlow.Instance?.OnEncounterCompleted(
                MapIntegration.Instance?.NodesCompleted ?? 0);
            if (GameFlow.Instance != null)
                GameFlow.Instance.ShowMapPanel();
            else
            {
                // ✅ [AUD-CDX-20602 Fix] GameFlow null 폴백에서 pause 해제 보장
                MapManager.Instance?.EndNodeInteractionPause();
                MapUI.Instance?.ShowMap();
            }
        }
    }

void OnStartRun()
    {
        // [AUD-CDX-31034] 재진입 방지 — 빠른 이중 클릭 시 환전/소모품 중복 실행 차단
        if (_isStarting) return;
        _isStarting = true;

        // 환전 처리 — [AUD-CDX-31027] 명시적 확인(Confirm) 시에만 실행
        // ✅ [2026-06-15 코덱스#258 Ex2] 즉시 커밋 제거 — RunStartFlow 에 ★예약★만 하고, 실제 런 시작 확정
        //   (TryStartGameWith[out]RunBible 의 IsRunStartRequestValid 통과) 직전에 커밋. 스테일/취소 시 폐기 → 토큰 유실 방지.
        if (_exchangeConfirmed && tokensToExchange > 0 && ExchangeSystem != null)
        {
            RunStartFlow.Instance?.SetPendingRunStartExchange(tokensToExchange);
        }
        tokensToExchange = 0;
        _exchangeConfirmed = false;

        // UI 닫기
        gameObject.SetActive(false);

        // ✅ [2026-06-13 Codex P2] 소모품 즉시효과 적용은 GameFlow.CommonRunInit(RunInit/성장/수정자 ★이후★)로 이동.
        //   기존엔 여기서 호출돼 StartLevel3 의 레벨업이 직후 RunInit(Level=1 리셋)에 덮였음. (여기 호출 제거)

#if UNITY_EDITOR || DEVELOPMENT_BUILD
        // ✅ 기지 전략 디버그 프리셋 (BaseLobbyUI 미구현 기간 테스트용)
        //    BaseStrategyManager Inspector에서 DebugPresetEnabled = true 설정 시 동작
        BaseStrategyManager.Instance?.ApplyDebugPreset();
#endif

        // ✅ RunStartFlow에 알림
        var runFlow = RunStartFlow.Instance;
        if (runFlow != null)
        {
            runFlow.OnRunStartComplete();
        }
        else
        {
            // Fallback: 직접 게임 시작
            var gameFlow = GameFlow.Instance;
            if (gameFlow != null)
            {
                gameFlow.StartRun();
            }
        }
    }

