private static bool UpgradeSkill(CharacterBase c)
    {
        var skillbook = c.GetComponent<PlayerSkillbook>();
        if (skillbook == null) skillbook = PlayerSkillbook.Instance;

        if (skillbook != null && skillbook.Skills != null && skillbook.Skills.Count > 0)
        {
            // ✅ [Fix] 실제 스킬 강화 구현 — 랜덤 스킬에 DamageMultiplier +15% 적용
            var randomSkill = skillbook.Skills[Random.Range(0, skillbook.Skills.Count)];
            // [Fix] DamageMultiplier 퍼센트 단위: 15 = +15% (내부에서 /100)
            // ✅ [AUD-CDX-257001 Fix] EnhanceSkill 반환값 검증 — 강화 상한 시 false → 아이템 소모 방지
            bool enhanced = skillbook.EnhanceSkill(randomSkill, SkillEnhancementType.DamageMultiplier, 15f);
            if (!enhanced)
            {
                ShowFeedback($"'{randomSkill.name}' already at enhance cap", Color.yellow);
                Debug.LogWarning($"[ItemEffect] UpgradeSkill → {randomSkill.name} 강화 상한 도달 — 아이템 소모 취소");
                return false;
            }

            ShowFeedback($"'{randomSkill.name}' Enhanced! +15%", Color.cyan);
            Debug.Log($"[ItemEffect] UpgradeSkill → {randomSkill.name} DamageMultiplier +15%");
            return true;
        }

        ShowFeedback("No skills to upgrade", Color.gray);
        return false;
    }

