private void OnUnlockAISkill(SkillDefinitionSO skill, int price)
        {
            int currentLevel = PlayerLevel.Instance?.Level ?? 1;
            if (skill != null && skill.UnlockLevel > currentLevel)
            {
                ShowMessage(Loc.Fmt("Skill/SkillMasterControllerComplete/L226", skill.UnlockLevel)); // 레벨 부족 (필요: Lv.{skill.UnlockLevel})
                return;
            }

            // ✅ [AUD-09004] GoldManager.CanAfford + MapIntegration.SpendGold 불일치 해소
            // MapIntegration.SpendGold 내부에서 GoldManager.CanAfford를 통해 검증 후 GameFlow.AddGold(-price)로 소비
            // 중복 GoldManager.CanAfford 제거 → SpendGold 단일 경로로 통일
            bool success = MapIntegration.Instance?.SpendGold(price) ?? false;
            if (!success)
            {
                ShowMessage(Loc.Fmt("Skill/SkillMasterControllerComplete/L232", price)); // 골드 부족! (필요: {price}G)
                Debug.LogError("[SkillMaster] AI 스킬 골드 차감 실패 (잔액 부족 또는 MapIntegration 없음)");
                return;
            }

            // 플레이어 스킬에 추가
            MapIntegration.Instance?.AddSkill(skill);

            // ✅ [AUD-CDX-261001 Fix] 실지급 확인 — AddSkill no-op 시 골드 환불
            var skillbook261 = PlayerLevel.Instance?.GetComponent<PlayerSkillbook>();
            bool delivered261 = skillbook261?.HasSkill(skill) ?? false;
            if (!delivered261)
            {
                // ✅ [AUD-CDX-274002 Fix] 세금 포함 환불 — 황금 서약 활성 시 실차감(price + tax) 전액 복구
                int _vowTax274ai = (BaseStrategyManager.Instance?.CurrentAbyssVow == "Gold")
                    ? Mathf.Max(0, Mathf.RoundToInt(price * BalanceConfig.GOLD_VOW_TAX_RATE)) : 0;
                int _refund274ai = price + _vowTax274ai;
                // ✅ [AUD-CDX-275001 Fix] GameFlow null 시 GoldManager 직접 환불 — MapIntegration.SpendGold fallback 경로로 차감된 골드 복구 보장
                if (GameFlow.Instance != null) GameFlow.Instance.AddGoldRefund(_refund274ai); // [Codex P2] 환불=통계 미기록
                else
                {
                    GoldManager.Instance?.AddGoldDirect(_refund274ai);
                    // ✅ [AUD-CDX-298002 Fix] AI 스킬 fallback 환불 즉시 커밋 — 환불-저장 원자성 보장
                    SaveManager.Instance?.SaveGame(forceImmediate: true);
                }
                ShowMessage(Loc.Get("Skill/Master/GoldInsufficient")); // 골드가 부족합니다! — 실지급 실패 메시지로 재사용
                Debug.LogWarning($"[SkillMaster] AI 스킬 지급 실패 (AddSkill no-op) — 골드 환불 {_refund274ai}G (세금 {_vowTax274ai}G 포함): {skill.name}");
                return;
            }

            // 카탈로그에서 제거 (중복 구매 방지)
            _aiSkills?.Remove(skill);

            RefreshSkillList();
            UpdateGoldDisplay();
            ShowMessage(Loc.Fmt("Skill/SkillMasterControllerComplete/L251", ResolveSkillDisplayName(skill))); // ✨ [AI 스킬] {skill.NameKey} 획득!
            GameFlow.Instance?.RequestMidRunSnapshot("SkillMaster.OnUnlockAISkill", true);
            Debug.Log($"[SkillMaster] AI 스킬 언락: {skill.NameKey} (-{price}G)");
        }

private List<LegacyWillEntry> ApplyInheritedWills(List<LegacyWillEntry> selected)
        {
            var actuallyGranted = new List<LegacyWillEntry>(); // ✅ [AUD-78101 Fix] 실제 지급 성공 항목만 추적

            var player    = PlayerLevel.Instance?.GetComponent<CharacterBase>();
            var relicSys  = player?.GetComponent<RelicEffectSystem>();
            var skillbook = PlayerSkillbook.Instance;

            foreach (var will in selected)
            {
                bool willGranted = false;
                if (will.Type == LegacyWillEntry.WillType.Relic && relicSys != null)
                {
                    // 유물 이름으로 SO 탐색 (서브폴더 폴백 포함)
                    var relicSO = ResolveRelicBySourceName(will.SourceName);
                    if (relicSO != null)
                    {
                        // ✅ [AUD-CDX-267001 Fix] AddRelic 결과 검증 — 실패 시 성공 메시지 오출력 방지
                        willGranted = relicSys.AddRelic(relicSO);
                        if (willGranted)
                            Debug.Log($"[LegacyWillSystem] 유언 유물 상속: {will.DisplayName}");
                        else
                            Debug.LogWarning($"[LegacyWillSystem] 유언 유물 상속 실패 (AddRelic 거부): {will.DisplayName}");
                    }
                    else
                    {
                        Debug.LogWarning($"[LegacyWillSystem] 유물 SO를 찾을 수 없음: {will.SourceName}");
                    }
                }
                else if (will.Type == LegacyWillEntry.WillType.Skill && skillbook != null)
                {
                    // 스킬 이름으로 SO 탐색 (서브폴더 폴백 포함)
                    var skillSO = ResolveSkillBySourceName(will.SourceName);
                    if (skillSO != null)
                    {
                        // ✅ [AUD-CDX-267001 Fix] 스킬 지급 전 보유 여부 확인 — no-op 시 성공 메시지 오출력 방지
                        bool hadBefore = skillbook.HasSkill(skillSO);
                        skillbook.AddSkill(skillSO);
                        willGranted = !hadBefore && skillbook.HasSkill(skillSO);
                        if (willGranted)
                            Debug.Log($"[LegacyWillSystem] 유언 스킬 상속: {will.DisplayName}");
                        else
                            Debug.LogWarning($"[LegacyWillSystem] 유언 스킬 상속 no-op (이미 보유): {will.DisplayName}");
                    }
                    else
                    {
                        Debug.LogWarning($"[LegacyWillSystem] 스킬 SO를 찾을 수 없음: {will.SourceName}");
                    }
                }

                // 성공 메시지는 실제 지급이 이루어진 경우에만 출력
                if (willGranted)
                {
                    actuallyGranted.Add(will);
                    MsgManager.Instance?.InputInstantMsg(
                        Loc.Fmt("Antigravity/LegacyWillSystem/L286", ResolveMaybeLocalized(will.DisplayName)), // 📜 [유언 상속] '{will.DisplayName}' 전승됨!
                        InstantMsgType.Good);
                }
            }

            // ✅ [AUD-78101 Fix] _inheritedThisRun에 실제 지급 성공 항목만 기록
            _inheritedThisRun = new List<LegacyWillEntry>(actuallyGranted);

            // ✅ [InheritedEffectScale] 상속 유물/스킬 적용 후 전투력 보정 적용
            // InheritedEffectScale = 0.7 → 플레이어 PhyPower/MagPower를 70%로 감쇠
            // MultDamage value = scale - 1f = -0.3 → stat *= (1 + (-0.3)) = stat * 0.7
            // ✅ [AUD-777-H002 Fix] selected.Count → actualGrantedCount: 지급 실패 시 감쇠 적용 방지
            if (actuallyGranted.Count > 0 && player != null && InheritedEffectScale < 1f)
            {
                ApplyInheritedScaleModifier(player);
            }

            return actuallyGranted;
        }

public void OnNodeMoved(NodeType nodeType)
        {
            // 전투 노드가 아닌 경우에만
            if (nodeType == NodeType.Combat || nodeType == NodeType.Elite ||
                nodeType == NodeType.Boss || nodeType == NodeType.MidBoss ||
                nodeType == NodeType.Seal) return;

            foreach (var skill in _activeSkills)
            {
                if (skill.Data == null) continue;
                if (skill.Data.EffectType == FieldSkillEffect.CompanionPartyHeal)
                {
                    // ✅ [Codex #268] 중앙 회복 정책 경유 — HealingService.Heal 이 NoHealing/맹세차단/맹세배율/
                    //    월드지변 배율 + NotifyHealUsed 를 일괄 처리. 기존 ApplyDeltaHP 직접호출은 맹세/지변 우회였음
                    //    (플레이어 필드스킬 SoulAbsorb·보상회복은 이미 HealingService 경유 — 정책 일관화).
                    //    NoHealing 조기 스킵 로그는 정보용 유지(HealingService 도 동일 체크하므로 무해).
                    if (RunModifierSystem.Instance != null && !RunModifierSystem.Instance.CanHeal())
                    {
                        Debug.Log($"[CompanionFieldSkill] {skill.CompanionName}: 야전 수리 차단 (NoHealing 수정자)");
                        continue;
                    }

                    float healRate = skill.EffectValue; // e.g., 0.03 = 3%
                    var companions = CompanionManager.Instance?.GetActiveCompanions();
                    if (companions == null) continue;

                    // 플레이어 + 동료 전체 회복 (HealingService 경유, 실제 회복량 추적)
                    bool anyHealed = false;
                    var player = PlayerLevel.Instance?.GetComponent<CharacterBase>();
                    if (player != null && player.Stat != null && !player.IsDead())
                    {
                        int healAmount = Mathf.Max(1, Mathf.RoundToInt(player.Stat.MaxHP * healRate));
                        if (HealingService.Heal(player, healAmount) > 0) anyHealed = true;
                    }
                    foreach (var comp in companions)
                    {
                        if (comp != null && comp.Stat != null && !comp.IsDead())
                        {
                            int healAmount = Mathf.Max(1, Mathf.RoundToInt(comp.Stat.MaxHP * healRate));
                            if (HealingService.Heal(comp, healAmount) > 0) anyHealed = true;
                        }
                    }
                    // NotifyHealUsed 는 HealingService.Heal 내부가 실제 회복 시 호출 → 수동 호출 제거(이중 알림 방지)
                    Debug.Log($"[CompanionFieldSkill] {skill.CompanionName}: 야전 수리 발동 ({healRate * 100:F0}% HP, healed={anyHealed})");
                }
            }
        }

private void OnClericNodeCompleted(CharacterBase player)
    {
        if (player == null || player.Stat == null) return; // [AUD-709-H002]
        // [Fix] NoHealing 수정자 체크
        if (RunModifierSystem.Instance != null && !RunModifierSystem.Instance.CanHeal()) return;

        float recoverRate = BalanceConfig.INSTINCT_CLERIC_HP_RECOVER * _metaMultiplier;
        int hpRecover = Mathf.Max(1, Mathf.RoundToInt(player.Stat.MaxHP * recoverRate));

        if (player.Stat.HP < player.Stat.MaxHP)
        {
            // ✅ [Codex #269] 중앙 회복 정책 경유 — HealingService.Heal 이 맹세차단/맹세배율/월드지변배율 + NotifyHealUsed 일괄.
            //    기존 ApplyDeltaHP 직접호출은 맹세/지변 우회였음(노드완료 맹세리젠 OathSystem L88 은 이미 HealingService 경유 → 정책 일관화).
            int healed = HealingService.Heal(player, hpRecover);
            if (healed > 0)
                MsgManager.Instance?.InputInstantMsg(
                    Loc.Fmt("Skill/ClassInstinctSystem/L203", healed), // 💡 [신의 은총] HP +{healed} 회복 (실제 회복량)
                    InstantMsgType.Normal);
        }
    }

public void AddSkill(SkillDefinitionSO skill)
        {
            if (PlayerSkillbook != null)
            {
                // ✅ [AUD-CDX-269001 Fix] 지급 전 보유 여부 확인 — no-op 시 사이드이펙트 오실행 방지
                bool hadBefore269 = PlayerSkillbook.HasSkill(skill);
                PlayerSkillbook.AddSkill(skill);
                bool effectivelyAdded269 = !hadBefore269 && PlayerSkillbook.HasSkill(skill);

                if (!effectivelyAdded269)
                {
                    Debug.LogWarning($"[MapIntegration] AddSkill no-op (이미 보유): {skill?.name} — 사이드이펙트 생략");
                    return;
                }

                Debug.Log($"[MapIntegration] +Skill: {skill.Dev.NameKo}");

                // 컬렉션 해금 기록 — 즉시 저장 제거 (AUD-145)
                // 조기 SaveGame() 및 RequestMidRunSnapshot(force:true)은 스킬은 저장되지만
                // 노드 방문 상태가 갱신되기 전이라 강제 종료 후 동일 스킬을 반복 획득 가능.
                // 저장은 OnEncounterCompleted → CompleteNode + RequestMidRunSnapshot 경로로만 수행.
                if (SaveManager.Instance?.CurrentSave != null)
                {
                    SaveManager.Instance.CurrentSave.UnlockSkill(skill.name);
                }

                // ✅ Phase 9.3 TASK-4: 스킬 획득 업적 기록
                // ★ [2026-06-15 Codex P2] saveNow:false — 노드 완료 전 저장 금지 가드 준수(카운터 farming 차단)
                AchievementManager.Instance?.RecordSkillCollect(saveNow: false);

                // 획득 팝업
                AcquirePopupUI.Instance?.ShowSkill(skill);
            }
        }

void OnBlessingSelected(BlessingSO blessing)
    {
        if (blessing == null)
        {
            Debug.LogWarning("[Rest] OnBlessingSelected called with null blessing.");
            return;
        }

        if (BlessingPanel != null) BlessingPanel.SetActive(false);

        string rawBK2 = !string.IsNullOrEmpty(blessing.NameKey) ? blessing.NameKey : blessing.name;
        string displayName = Loc.Get(rawBK2);
        if (string.IsNullOrEmpty(displayName)) displayName = rawBK2;

        Debug.Log($"[Rest] Blessing selected: {displayName}");

        // ✅ 실제 축복 적용 — MapIntegration.AddBlessing(id) 사용
        // ✅ [AUD-CDX-271001 Fix] 커밋 성공 후 hasBlessing 설정 — 사전 성공 래치 방지
        string blessingId = !string.IsNullOrEmpty(blessing.BlessingId) ? blessing.BlessingId : blessing.name;
        bool blessingApplied271 = false;
        if (MapIntegration.Instance != null)
        {
            blessingApplied271 = MapIntegration.Instance.TryAddBlessing(blessingId);
            if (!blessingApplied271)
                Debug.LogWarning($"[Rest] Blessing apply failed via MapIntegration: {blessingId}");
        }
        else
        {
            // MapIntegration 없으면 BlessingManager에 직접 Grant
            var mgr = BlessingManager.Instance;
            if (mgr != null)
            {
                mgr.Grant(blessing);
                blessingApplied271 = true;
            }
            else
                Debug.LogWarning("[Rest] Neither MapIntegration nor BlessingManager found — blessing not applied.");
        }

        if (blessingApplied271)
        {
            hasBlessing = true;
            UpdateOptions();

            // Update narration
            if (RestNarratorText != null)
            {
                RestNarratorText.text = Loc.Fmt("UI/Correct_RestSiteUI/L1156", displayName); // {displayName}을(를) 받았다!
            }
        }

        // ✅ [RunPrep] prep_karma_surge — 축복 2개 동시 획득
        if (_prepKarmaSurgeActive)
        {
            _prepKarmaSurgeActive = false; // 1회만 발동
            var allBlessingsForKarma = CollectionManager.Instance != null
                ? CollectionManager.Instance.GetAllBlessingsCached()
                : Resources.LoadAll<BlessingSO>("Blessings");
            if (allBlessingsForKarma != null && allBlessingsForKarma.Length > 0)
            {
                var candidates = new System.Collections.Generic.List<BlessingSO>();
                foreach (var b in allBlessingsForKarma)
                {
                    if (b != null && b != blessing) candidates.Add(b);
                }
                if (candidates.Count > 0)
                {
                    var bonus = candidates[Random.Range(0, candidates.Count)];
                    string bonusId = !string.IsNullOrEmpty(bonus.BlessingId) ? bonus.BlessingId : bonus.name;
                    // ✅ [AUD-CDX-229003 Fix] TryAddBlessing 반환값 검증 — 실패 시 성공 메시지 오출력 방지
                    // ✅ [AUD-CDX-271002 Fix] BlessingManager null 시 blessingAdded 오설정 방지
                    bool blessingAdded;
                    if (MapIntegration.Instance != null)
                        blessingAdded = MapIntegration.Instance.TryAddBlessing(bonusId);
                    else
                    {
                        var bonusMgr = BlessingManager.Instance;
                        if (bonusMgr != null)
                        {
                            bonusMgr.Grant(bonus);
                            blessingAdded = true;
                        }
                        else
                            blessingAdded = false;
                    }

                    if (blessingAdded)
                    {
                        string bonusName = Loc.Get(!string.IsNullOrEmpty(bonus.NameKey) ? bonus.NameKey : bonus.name);
                        if (string.IsNullOrEmpty(bonusName)) bonusName = bonus.name;
                        MsgManager.Instance?.InputInstantMsg(
                            Loc.Fmt("UI/Correct_RestSiteUI/KarmaSurge", bonusName), InstantMsgType.Good);
                        Debug.Log($"[RunPrep] prep_karma_surge 발동: 보너스 축복 {bonusId}");
                    }
                    else
                        Debug.LogWarning($"[RunPrep] prep_karma_surge 보너스 축복 지급 실패: {bonusId}");
                }
            }
        }

        // ✅ [검증 #31] 축복 선택 후 즉시 스냅샷 — 앱 강제종료 시 축복 상태 보존
        GameFlow.Instance?.RequestMidRunSnapshot("RestSiteUI.Blessing", force: true);
        // ✅ [AUD-BUFF-Phase40 Fix] 축복 지급 후 즉시 디스크 커밋 — 강제 종료 리롤 방지
        SaveManager.Instance?.SaveGame(forceImmediate: true);
    }

private void ApplyPrayEffect()
        {
            float roll = Random.value;
            float enhanceMul = 1f + FieldSkillExecutor.GetAltarEnhanceRate();

            string result;

            if (roll < 0.3f)  // 30% - 좋은 효과
            {
                int goldBonus = Mathf.RoundToInt(Random.Range(50, 101) * enhanceMul);
                // AltarPray Fix: AddGold → GameFlow.AddGold 경유
                bool goldOk;
                if (GameFlow.Instance != null)
                {
                    // ✅ [AUD-CDX-151002 Fix] AddGold 반환값 검증 — 지급 실패 시 메시지 억제
                    goldOk = GameFlow.Instance.AddGold(goldBonus);
                    if (!goldOk)
                        Debug.LogWarning($"[Altar] 골드 지급 실패 — GameFlow.AddGold({goldBonus}) false 반환");
                }
                else
                {
                    // ✅ [AUD-CDX-21502 Fix] GameFlow null 폴백 — 보상 소실 방지 (통계 미기록 감수)
                    goldOk = GoldManager.Instance != null;
                    GoldManager.Instance?.AddGoldDirect(goldBonus);
                    SaveManager.Instance?.SaveGame(forceImmediate: true); // ✅ [AUD-CDX-306001] 폴백 골드 즉시 커밋
                    Debug.LogWarning($"[Altar] GameFlow 없음 — 골드 직접 지급(통계 미기록): {goldBonus}");
                }

                result = goldOk
                    ? Loc.Fmt("Map/Altar/PrayGold", goldBonus) // ✨ 신의 은총 기도가 받아들여졌습니다! 💰 +{0} 골드 축복이 함께 하길...
                    : Loc.Get("Map/Altar/PrayNoEffect"); // 🙏 평온한 기도. 마음이 평온해집니다. 특별한 효과는 없습니다.
            }
            else if (roll < 0.6f)  // 30% - 평범한 효과
            {
                if (Player != null && Player.Stat != null)
                {
                    // ✅ [Codex #272] HealingService 경유 — NoHealing/맹세차단/맹세배율/지변배율 + NotifyHealUsed 일괄.
                    //    기존 직접 ApplyDeltaHP 는 맹세·지변 우회였음(ApplyHealModifier조차 없어 지변도 미적용).
                    //    raw healAmount 전달 → HealingService 가 배율 적용, 결과 메시지는 실제 회복량 기준.
                    int healAmount = Mathf.RoundToInt(Player.Stat.MaxHP * 0.3f * enhanceMul);
                    int actualHeal = HealingService.Heal(Player, healAmount);
                    result = actualHeal > 0
                        ? Loc.Get("Map/Altar/PrayHeal") // 🙏 평온한 기도 마음이 평온해집니다. ❤️ HP 30% 회복 신의 평안이 함께 하길...
                        : Loc.Get("Map/Altar/PrayNoEffect"); // 🙏 평온한 기도. 마음이 평온해집니다. 특별한 효과는 없습니다.
                }
                else
                {
                    result = Loc.Get("Map/Altar/PrayNoEffect"); // 🙏 평온한 기도 마음이 평온해집니다. 특별한 효과는 없습니다.
                }
            }
            else  // 40% - 아무 효과 없음
            {
                result = Loc.Get("Map/Altar/PraySilence"); // ... 침묵 ... 신은 대답하지 않습니다. 아무 일도 일어나지 않았습니다.
            }

            ShowResult(Loc.Get("Map/Altar/PrayResultTitle"), result); // 기도의 결과
        }

private void ApplyStatBonus(StatType statType)
        {
            if (Player == null || Player.Ability == null || Player.Stat == null) return;

            int bonus = GetStatBonus(statType);

            switch (statType)
            {
                case StatType.STR:
                    Player.Ability.STR += bonus;
                    PlayerLevel.Instance?.Rules?.Recalc(Player); // ✅ [Codex #275] 파생 물리공격력 즉시 반영
                    break;

                case StatType.DEX:
                    Player.Ability.DEX += bonus;
                    PlayerLevel.Instance?.Rules?.Recalc(Player); // ✅ [Codex #275] 명중/회피/치명/속도/물공 즉시 반영
                    break;

                case StatType.CON:
                    Player.Ability.CON += bonus;
                    // ✅ Fix: StatRulesSO.Recalc() 경유로 MaxHP를 공식에 맞게 재계산
                    // (Stat.MaxHP 직접 수정 대신 Recalc 사용하여 수식 일관성 유지)
                    {
                        var rules = PlayerLevel.Instance?.Rules;
                        if (rules != null)
                        {
                            float prevMaxHP = Player.Stat.MaxHP;
                            rules.Recalc(Player);
                            // 훈련 보너스: MaxHP 증가분만큼 현재 HP도 회복 (ApplyDeltaHP 경유)
                            float delta = Player.Stat.MaxHP - prevMaxHP;
                            if (delta > 0) Player.ApplyDeltaHP(Mathf.RoundToInt(delta));
                        }
                        else
                        {
                            // Rules 없을 시 BalanceConfig 기준 폴백
                            float hpBonus = bonus * BalanceConfig.HP_PER_CON;
                            Player.Stat.MaxHP += hpBonus;
                            Player.ApplyDeltaHP(Mathf.RoundToInt(hpBonus));
                        }
                    }
                    break;

                case StatType.INT:
                    Player.Ability.INT += bonus;
                    PlayerLevel.Instance?.Rules?.Recalc(Player); // ✅ [Codex #275] 마법공격력/MaxMP/MP재생/쿨감 즉시 반영
                    break;

                case StatType.WIS:
                    Player.Ability.WIS += bonus;
                    // ✅ Fix: Recalc으로 MagDef/RegenHP 재계산 (WIS는 공식상 MaxMP에 직접 연결 없음)
                    // MaxMP 보너스는 UI 표시 일관성을 위해 수동으로 추가 (3f per WIS 유지)
                    {
                        var rules = PlayerLevel.Instance?.Rules;
                        if (rules != null) rules.Recalc(Player);

                        float mpBonus = bonus * 3f;  // WIS→MaxMP 수동 보너스 (UI: "최대 MP 증가")
                        Player.Stat.RewardBonusMaxMP += mpBonus; // Recalc 영속 레이어에 기록
                        Player.Stat.MaxMP += mpBonus; // Recalc 이후이므로 즉시 반영
                        Player.ApplyDeltaMP(mpBonus);
                    }
                    break;

                case StatType.CHA:
                    Player.Ability.CHA += bonus;
                    PlayerLevel.Instance?.Rules?.Recalc(Player); // ✅ [Codex #275] 골드획득/상점할인/이벤트성공 즉시 반영
                    break;
            }

            Debug.Log($"[Training] {statType} increased by {bonus}");
        }

void OnItemSelected(ItemSO item)
    {
        Debug.Log($"[Combat] Item selected: {item.NameKey}");

        // ✅ [Auto_488#F1] BattleController 경유 아이템 사용 — 턴 진행 및 효과 처리 위임
        if (BattleController != null)
        {
            BattleController.UseItemBySelection(item);
            CloseItemPanel();
            return;
        }

        // BattleController 없을 때 직접 처리 (레거시 폴백)
        var player = PlayerLevel.Instance?.GetComponent<CharacterBase>();
        var rules = PlayerLevel.Instance?.Rules;

        if (player != null && rules != null)
        {
            // ✅ [Codex #277] 레거시 폴백도 백엔드 엔트리 사용 API(UseItemEntry)로 통일 — 기존 ApplyItem+RemoveItem(itemId)
            //   조합은 맹세 아이템차단/NoItems 모디파이어/챌린지 사용추적/미드런 스냅샷·즉시저장/엔트리정체성(강화배율 오-차감)을
            //   모두 우회했음. UseItemEntry 가 효과적용+차단체크+선택엔트리 직접차감+스냅샷/저장을 일괄 수행(주 경로와 통일).
            var inv = InventorySystem_TRPG.Instance;
            var uiItemEntry = inv?.Items.FirstOrDefault(e => e.Item?.ItemId == item.ItemId);
            if (uiItemEntry != null)
                inv.UseItemEntry(uiItemEntry);
            else
                Debug.LogWarning($"[CombatUI] 레거시 폴백 — 인벤 엔트리 없음, 사용 취소: {item?.ItemId}");
        }

        CloseItemPanel();
    }
